var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"…나이엘 블루스틸, 970점!","JPN":"……ナイエル・ブルースチール、970点！","ENG":"...Naielle Bluesteel, 970 points!","TWN":"奈爾‧布魯斯提爾，970分！"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"케이시 빈즈, 972점!","JPN":"ケイシー・ビンズ、972点！","ENG":"Kaci Bins, 972 points!","TWN":"卡西‧比恩茲，972分！"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"이상으로 체력실기 중간발표를 마친다!","JPN":"体力実技の中間発表は以上！","ENG":"This concludes the midterm physical fitness evaluation!","TWN":"以上為體能評測成績的中場得分！"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"STUDENT_EXTRA_NULL_NULL","text":{"KOREA":"나이엘도 굉장하지만, 저 초등부 꼬마도 대단하네.","JPN":"ナイエルもすごいけど、初等部のあのチビも負けてないね。","ENG":"Naielle is fantastic, but that elementary school kid is equally impressive.","TWN":"奈爾已經很誇張了，那個小學部的小鬼也太厲害了吧。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STUDENT_EXTRA_NULL_NULL","text":{"KOREA":"그러게. 지난 번 운동회 때도 비슷한 광경을 본 것 같은데.","JPN":"そうだね。前回の運動会でも同じ光景を見た気がするよ。","ENG":"Yeah. I believe I saw something similar to this at the last field day.","TWN":"對啊，上次運動會的時候，好像看過類似的場面。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"좋아! 다들 지난 번보다 종합성적이 올라갔네! 조금만 더 힘내도록 해!","JPN":"よし！　みんな前回より総合成績が上がったね！　もう少しだけ頑張ろう！","ENG":"Okay! Everyone's overall results have improved since the last time! Keep giving it your best!","TWN":"好！大家的綜合成績都比上次進步了！再加油喔！"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"잠깐만! 채점 기준이 이상하잖아요!","JPN":"ちょっと！　採点基準がおかしいんじゃないの！？","ENG":"Hold on! Something is wrong with the scoring criteria!","TWN":"等一下！這個評分標準也太奇怪了吧！"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"장거리 달리기라면서 무기를 들고 뛰게 하는 엉터리 시험이 어딨어!","JPN":"武器を持たせて長距離を走らせるなんて、無茶苦茶よ！","ENG":"What kind of test requires you to run long distances while carrying a weapon?","TWN":"明明說是長跑，結果卻要拿著武器跑，哪有這種亂七八糟的考試啊！"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"그야 이 시험은 어디까지나 실전 기반의 평가이니까.","JPN":"このテストはあくまで実戦を基にした環境での評価なのよ。","ENG":"That's because this evaluation is based on real-world scenarios.","TWN":"那是因為這本來就是以實戰為基礎，進行評估的測驗啊。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"그래서 전투력 측정 때도 각자 자기 무기를 쓰게 했잖니?","JPN":"だから戦闘力測定の時も、自分の武器を使わせたんでしょう？","ENG":"It's also why I asked everyone to bring their own weapon when we were evaluating combat power.","TWN":"所以才會在測定戰鬥力時，讓大家使用各自的武器不是嗎？"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"그치이-? 케이시?","JPN":"ね？　ケイシー？","ENG":"Isn't that right, Kaci?","TWN":"對吧～？卡西？"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"…히끅.","JPN":"……ひっく。","ENG":"*...Hiccup*","TWN":"……嗝。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"인정 못해! 초엘리트인 내가 저런 초등부 꼬맹이한테 순위가 밀리는 건 말도 안되잖아요!","JPN":"認めないよ！　超エリートの私が、あんな初等部のチビより劣るなんてありえない！","ENG":"This is unacceptable! How can I, a super elite, be ranked lower than this kid?!","TWN":"我不管！我這種超級菁英的名次，怎麼可能被那種小學部的小鬼超過啊！"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"한심한 녀석! 아카데미 최고의 에이스가 결판이 나기도 전에 포기하려는 거냐!","JPN":"情けないことを言わないの！　アカデミー最高のエースが最後まで戦わずして諦めるつもり！？","ENG":"Stop acting like a sore loser! Is the Academy's best ace giving up before seeing the final results?!","TWN":"真令人心寒！身為學院最強王牌，居然在分出勝負前就想放棄嗎！"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"크윽…?!","JPN":"くっ……！？","ENG":"Krrgh...?!","TWN":"唔嗚……？！"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"흥…! 하긴 그 말도 일리는 있네.","JPN":"ふん……！　確かに、その言葉は一理あるね。","ENG":"Hmph...! I guess you have a point there.","TWN":"哼……！你這麼說也沒錯啦。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"중간과정이야 어찌됐건, 결국 우승은 이 에이스님의 차지가 될 테니 말이야.","JPN":"中間結果がどうであれ、最後に優勝するのはこのエース、ナイエル様だからね。","ENG":"It doesn't matter what the process is like because this ace is going to come out on top.","TWN":"不管過程如何，最後的優勝一定是我這個王牌的！"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"아하하하핫!!!","JPN":"あははははっ！！","ENG":"A ha ha ha ha!!","TWN":"啊哈哈哈哈！！"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"STUDENT_EXTRA_NULL_NULL","text":{"KOREA":"역시 나이엘이야! 운동회가 아닌 체력실기에서조차 우승을 노리다니!","JPN":"さすがナイエル！　運動会だけじゃなく体力実技でも優勝を狙うなんて！","ENG":"That's the Naielle we know! She's aiming for first place even in this physical fitness evaluation!","TWN":"果然是奈爾！就連不是運動會的體能評測，也只想奪冠！"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"STUDENT_EXTRA_NULL_NULL","text":{"KOREA":"영광이라곤 없는 평가전에서조차 최선을 다하는 모습! 그야말로 아카데미의 최강 엘리트다워!","JPN":"なんの栄誉も与えられない評価戦でも全力を尽くす姿……！　まさにアカデミー最強のエリートだ！","ENG":"Doing her best in the evaluations, even if it does not result in any recognition! She truly represents the Academy's elite!","TWN":"就算是沒有榮譽的評價測驗，也全力以赴的姿態！不愧是學院最強的菁英！"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"헥… 헥…","JPN":"ぜえ……ぜえ……","ENG":"*Huff* *Huff*","TWN":"呼……呼……"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"어찌저찌 점수를 벌려 놓긴 했지만, 아직 안심하긴 일러.","JPN":"なんとか点差はひらいておいたけど、まだ油断はできない。","ENG":"I managed to widen the score gap, but I'm not done yet.","TWN":"雖然勉強拉開分數，但現在還不能大意。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"저 꼬맹이… 설마 운동회 때 보여준 모습도 우연이 아니었던 건가?","JPN":"あのチビ……まさか、運動会での勢いも偶然ではなかった…？","ENG":"That kid... was her performance at field day not a fluke?","TWN":"那個小鬼……難道她在運動會上的表現，也不是偶然嗎？"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"…그럼 마지막 종목은 정확도 테스트야.","JPN":"……では、最後の種目は正確度テストよ。","ENG":"...The last evaluation will be an accuracy test.","TWN":"……那麼，最後一項是準確度測試。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"운동장 가운데서 공을 골대에 넣기만 하면 돼. 간단하지?","JPN":"グラウンドの真ん中から、ボールをゴールに入れるだけ。簡単でしょう？","ENG":"You just have to put the ball into the goal from the center of the field. Simple, right?","TWN":"只要在操場中央，把球踢進球門就好。很簡單吧？"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"그럼, 이번엔 케이시부터 시작해볼까?","JPN":"それでは今回はケイシーから始めようか？","ENG":"Then, Kaci? Would you like to start?","TWN":"那就，這次先從卡西開始吧。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"…에잇!","JPN":"……えいっ！","ENG":"...Egh!","TWN":"……嘿！"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"총소리…?!","JPN":"銃声……！？","ENG":"A gunshot...?!","TWN":"槍聲……？！"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"공이 사라졌어?!","JPN":"ボールが消えた……！？","ENG":"Where did the ball go?!","TWN":"球不見了？！"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};